module ring_counter_8bit (count, clk, reset, en);
   input clk, reset, en;
   output [7:0] count;

   reg [7:0] count;

     wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge reset or posedge dbg_halt) begin
      if (reset)
         count <= 8'b0000_0001;
      else if (en)
         count <= {count[6:0], count[7]};
   end

endmodule
